import {
  ChangeDetectionStrategy,
  Component,
  OnInit,
  computed,
  inject,
  signal,
} from '@angular/core';
import { RouterLink } from '@angular/router';
import { ApiService, DashboardSummary } from '../core/api.service';
import { CrmTask } from '../core/models';

@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [RouterLink],
  templateUrl: './dashboard.component.html',
  styleUrl: './dashboard.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class DashboardComponent implements OnInit {
  private readonly api = inject(ApiService);

  loading = signal(true);

  summary = signal<DashboardSummary>({
    accounts: 0,
    contacts: 0,
    openOpportunities: 0,
    upcomingTasks: 0,
  });

  upcomingTasks = signal<CrmTask[]>([]);

  stats = computed(() => {
    const s = this.summary();
    return [
      { key: 'accounts', label: 'Accounts', value: s.accounts, icon: '🏢', link: '/accounts' },
      { key: 'contacts', label: 'Contacts', value: s.contacts, icon: '👤', link: '/contacts' },
      { key: 'opps', label: 'Open Opportunities', value: s.openOpportunities, icon: '💰', link: '/opportunities' },
      { key: 'tasks', label: 'Upcoming Tasks', value: s.upcomingTasks, icon: '✓', link: '/tasks' },
    ];
  });

  async ngOnInit(): Promise<void> {
    this.loading.set(true);
    try {
      const [summary, tasks] = await Promise.all([
        this.api.dashboardSummary(),
        this.api.upcomingTasks(),
      ]);
      this.summary.set(summary);
      this.upcomingTasks.set(tasks);
    } catch {
      /* 401 is handled centrally; other failures leave the empty state visible. */
    } finally {
      this.loading.set(false);
    }
  }
}
